33	impl Idle {
34	    pub(super) fn new(num_workers: usize) -> (Idle, Synced) {
35	        let init = State::new(num_workers);
36	
37	        let idle = Idle {
38	            state: AtomicUsize::new(init.into()),
39	            num_workers,
40	        };
41	
42	        let synced = Synced {
43	            sleepers: Vec::with_capacity(num_workers),
44	        };
